scwin.f_validate = function () {
  //반출
  if (ds_resultsCopino1.getRowCount() > 0 && cbx_crryOutCopino.getSelectedIndex() == "1") {
    // if (!$c.gus.cfValidate([tb_crryOutCopino])) { 퍼블 다시 수정해야함
    // 	return false;
    // }
    //[사전정보그룹구분=터미널]이면 차량ID를 입력받아야함
    if (ds_resultsCopino1.getCellData(0, "preInfoGrpClsCd") == DsConstants.EDI_GRPCD_TM && ds_resultsCopino1.getCellData(0, "vehclIdCardNo") == "") {
      $c.gus.cfAlertMsg($p, "[사전정보그룹구분]이 터미널 일때 [차량ID카드번호]는 필수입니다");
      return false;
    }

    //[full/empty구분=full]이면 SEAL NO를 입력받아야함
    if (ds_resultsCopino1.getCellData(0, "fullEmptyClsCd") == DsConstants.EDI_FULL_EMPTY_CLS_FULL && ds_resultsCopino1.getCellData(0, "sealNo") == "") {
      $c.gus.cfAlertMsg($p, "[E/F 구분]이 FULL 일때 [SEAL NO]는 필수입니다");
      return false;
    }
    var v_features = "copyHeader=yes,rowFrom=1,rowCnt=1";
    $c.gus.cfCopyDataSet($p, ds_resultsCopino1, ds_resultsCopino3, v_features);
  }
  //반입
  if (ds_resultsCopino2.getRowCount() > 0 && cbx_crryInCopino.getSelectedIndex() == "1") {
    // if (!cfValidate([tb_crryInCopino])) {
    // 	return false;
    // }
    //[수입수출구분=수출, full/empty구분=full]이면 bookingNo를 입력받아야함
    //if (ds_resultsCopino2.setCellData(0, "impExpDomesticClsCd") ==  DsConstants.IMP_EXP_CLS_CD_EXP
    //	&& ds_resultsCopino2.setCellData(0, "fullEmptyClsCd") ==  DsConstants.EDI_FULL_EMPTY_CLS_FULL
    //	&& ds_resultsCopino2.setCellData(0, "bookingNo") == "") {
    //	cfAlertMsg("[E/F 구분]이 FULL 일때 [B/K NO]는 필수입니다");
    //	return false;
    //}
    //[full/empty구분=full]이면 WEIGHT를 입력받아야함
    if (ds_resultsCopino2.getCellData(0, "fullEmptyClsCd") == DsConstants.EDI_FULL_EMPTY_CLS_FULL && (ds_resultsCopino2.getCellData(0, "totWt") == 0 || ds_resultsCopino2.getCellData(0, "totWt") == "")) {
      $c.gus.cfAlertMsg($p, "[E/F 구분]이 FULL 일때 [WEIGHT]는 필수입니다");
      return false;
    }
    //[사전정보그룹구분=터미널]이면 차량ID를 입력받아야함
    if (ds_resultsCopino2.getCellData(0, "preInfoGrpClsCd") == DsConstants.EDI_GRPCD_TM && ds_resultsCopino2.getCellData(0, "vehclIdCardNo") == "") {
      $c.gus.cfAlertMsg($p, "[사전정보그룹구분]이 터미널 일때 [차량ID카드번호]는 필수입니다");
      return false;
    }
    //[사전정보그룹구분=터미널]이면 모선/항차를 입력받아야함
    if (ds_resultsCopino2.getCellData(0, "preInfoGrpClsCd") == DsConstants.EDI_GRPCD_TM && ds_resultsCopino2.getCellData(0, "tmlVsslPortcnt") == "") {
      $c.gus.cfAlertMsg($p, "[사전정보그룹구분]이 터미널 일때 [모선/항차]는 필수입니다");
      return false;
    }
    //[full/empty구분=full]이면 SEAL NO를 입력받아야함
    if (ds_resultsCopino2.getCellData(0, "fullEmptyClsCd") == DsConstants.EDI_FULL_EMPTY_CLS_FULL && ds_resultsCopino2.getCellData(0, "sealNo") == "") {
      $c.gus.cfAlertMsg($p, "[E/F 구분]이 FULL 일때 [SEAL NO]는 필수입니다");
      return false;
    }
    var v_features = "copyHeader=yes,rowFrom=1,rowCnt=1";
    $c.gus.cfCopyDataSet($p, ds_resultsCopino2, ds_resultsCopino4, v_features);
  }
  if (ds_resultsCopiCodeco1.getRowCount() > 0 && cbx_crryOutCopiCodeco.getSelectedIndex() == "1") {
    // if (!cfValidate([tb_crryOutCopiCodeco])) {
    // 	return false;
    // }

    //대한통운 일경우 컨테이너번호 필수
    if (ds_resultsCopiCodeco1.getCellData(0, "cls") == "DT") {
      if ($c.gus.cfIsNull($p, ds_resultsCopiCodeco1.getCellData(0, "cntrNo"))) {
        $c.gus.cfAlertMsg($p, "작업지역이 [대한통운] 일경우 [컨테이너번호]는 필수 입니다.");
        return false;
      }
    }
    var v_features = "copyHeader=yes,rowFrom=1,rowCnt=1";
    $c.gus.cfCopyDataSet($p, ds_resultsCopiCodeco1, ds_resultsCopiCodeco3, v_features);
  }
  if (ds_resultsCopiCodeco2.getRowCount() > 0 && cbx_crryInCopiCodeco.getSelectedIndex() == "1") {
    // if (!cfValidate([tb_crryInCopiCodeco])) {
    // 	return false;
    // }

    //대한통운 일경우 컨테이너번호 필수
    if (ds_resultsCopiCodeco2.getCellData(0, "cls") == "DT") {
      if ($c.gus.cfIsNull($p, ds_resultsCopiCodeco2.getCellData(0, "cntrNo"))) {
        $c.gus.cfAlertMsg($p, "작업지역이 [대한통운] 일경우 [컨테이너번호]는 필수 입니다.");
        return false;
      }
    }
    var v_features = "copyHeader=yes,rowFrom=1,rowCnt=1";
    $c.gus.cfCopyDataSet($p, ds_resultsCopiCodeco2, ds_resultsCopiCodeco4, v_features);
  }
  return true;
};

